+/**
+ * Notifications Routes - REST API endpoints for notification management.
+ *
+ * Provides endpoints for:
+ * - Listing and filtering notifications
+ * - Marking notifications as read
+ * - Executing notification actions
+ * - Managing notification preferences
+ * - Sending test notifications
+ */
+
+import { type Context, Hono } from "hono";
+import { z } from "zod";
+import { getLogger } from "../middleware/correlation";
+import type {
+  NotificationCategory,
+  NotificationChannel,
+  NotificationFilter,
+  NotificationPriority,
+  NotificationStatus,
+} from "../models/notification";
+import {
+  createNotification,
+  executeAction,
+  getNotification,
+  getNotifications,
+  getPreferences,
+  markAllAsRead,
+  markAsRead,
+  sendTestNotification,
+  updatePreferences,
+} from "../services/notification.service";
+import {
+  sendError,
+  sendInternalError,
+  sendList,
+  sendNotFound,
+  sendResource,
+  sendValidationError,
+} from "../utils/response";
+import { transformZodError } from "../utils/validation";
+
+const notifications = new Hono();
+
+// ============================================================================
+// Validation Schemas
+// ============================================================================
+
+const ActionSchema = z.object({
+  actionId: z.string().min(1, "Action ID is required"),
+});
+
+const PreferencesUpdateSchema = z.object({
+  enabled: z.boolean().optional(),
+  defaultChannels: z
+    .array(z.enum(["in_app", "email", "slack", "webhook"]))
+    .optional(),
+  quietHours: z
+    .object({
+      enabled: z.boolean().optional(),
+      start: z
+        .string()
+        .regex(/^([01]\d|2[0-3]):([0-5]\d)$/, "Must be HH:MM format")
+        .optional(),
+      end: z
+        .string()
+        .regex(/^([01]\d|2[0-3]):([0-5]\d)$/, "Must be HH:MM format")
+        .optional(),
+      timezone: z.string().optional(),
+      allowUrgent: z.boolean().optional(),
+    })
+    .optional(),
+  categories: z
+    .record(
+      z.enum(["agents", "coordination", "tasks", "costs", "security", "system"]),
+      z.object({
+        enabled: z.boolean().optional(),
+        channels: z
+          .array(z.enum(["in_app", "email", "slack", "webhook"]))
+          .optional(),
+        minPriority: z.enum(["low", "normal", "high", "urgent"]).optional(),
+      }),
+    )
+    .optional(),
+  digest: z
+    .object({
+      enabled: z.boolean().optional(),
+      frequency: z.enum(["daily", "weekly"]).optional(),
+      timeOfDay: z
+        .string()
+        .regex(/^([01]\d|2[0-3]):([0-5]\d)$/, "Must be HH:MM format")
+        .optional(),
+      timezone: z.string().optional(),
+    })
+    .optional(),
+  channelConfig: z
+    .object({
+      email: z.object({ address: z.string().email().optional() }).optional(),
