+// Event Listeners
+// ============================================================================
+
+/**
+ * Register a notification listener.
+ */
+export function onNotification(listener: NotificationListener): () => void {
+  listeners.push(listener);
+  return () => {
+    const index = listeners.indexOf(listener);
+    if (index >= 0) {
+      listeners.splice(index, 1);
+    }
+  };
+}
